MERGE INTO CONSULTAS FIN USING (SELECT '002766SubSDF_FLORENCIA' INFORME ,TO_CLOB(q'[SELECT DISTINCT COMPANIA,
  TIPOMOVIMIENTO,
  MOVIMIENTO ENTRDEVOLUTIVO,
  LPAD(ELEMENTO,3) AS EXPR1,
  SUM(VALORTOTAL)  AS SUMADEVALORTOTAL
FROM D_MOVIMIENTO
WHERE COMPANIA       = '$P!{PR_COMPANIA}'
  AND TIPOMOVIMIENTO = '$P!{PR_TIPOMOVIMIENTO}' 
  AND MOVIMIENTO     = $P!{PR_ENTRDEVOLUTIVO}
GROUP BY COMPANIA,
  TIPOMOVIMIENTO,
  MOVIMIENTO,
  LPAD(ELEMENTO,3)]') CONSULTA, 10 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);

MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002765SDF_FLORENCIA' INFORME_PADRE, '002766SubSDF_FLORENCIA' INFORME_HIJO, 'PR_SUBINFORME_D_ENTDEVOLUTIVO' PARAMETRO ,NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);